#include <bits/stdc++.h>
#include <vector>
#include <algorithm>

using namespace std;

int main()
{
    int n;
    cin >> n;
    vector<int> v(n);
    v[0] = 1;
    for (int i = 1; i < n; i++)
    {
        int x;
        cin >> x;
        v[i] = v[x - 1] + 1;
    }
    for (int i = 0; i < n; i++)
    {
        cout << v[i] << " ";
    }
    return 0;
}
